// Expo config plugin: release signing driven by Gradle properties.
//
// android/ is generated by prebuild and gitignored, so the release signing
// config can't live in a committed gradle file. This plugin injects it during
// prebuild. It is GUARDED: the release build type uses the upload keystore only
// when the `VESTA_UPLOAD_STORE_FILE` Gradle property is present (set from CI
// secrets by .github/workflows/release.yml via ORG_GRADLE_PROJECT_* env vars),
// and otherwise falls back to the debug keystore. So local dev builds and the
// normal CI Android Build (which set no such property) are completely
// unaffected — they keep signing with the debug key exactly as before.
//
// See docs/RELEASING.md for the keystore + secrets setup.

const { withAppBuildGradle } = require("expo/config-plugins");

// A release signing config that only reads the keystore when the property is
// set. When it isn't, the block is empty and simply never referenced.
const RELEASE_SIGNING_CONFIG = `        release {
            if (project.hasProperty('VESTA_UPLOAD_STORE_FILE')) {
                storeFile file(VESTA_UPLOAD_STORE_FILE)
                storePassword VESTA_UPLOAD_STORE_PASSWORD
                keyAlias VESTA_UPLOAD_KEY_ALIAS
                keyPassword VESTA_UPLOAD_KEY_PASSWORD
            }
        }
`;

// Uniquely identifies the release build type's signing line via the stock Expo
// comment that precedes it, so we never touch the debug build type's.
const RELEASE_BUILDTYPE_SIGNING =
  /(release \{\n\s*\/\/ Caution![^\n]*\n\s*\/\/ see[^\n]*\n)\s*signingConfig signingConfigs\.debug/;

module.exports = function withAndroidSigning(config) {
  return withAppBuildGradle(config, (cfg) => {
    let src = cfg.modResults.contents;

    if (src.includes("VESTA_UPLOAD_STORE_FILE")) {
      return cfg; // already applied — idempotent across repeated prebuilds
    }

    if (!RELEASE_BUILDTYPE_SIGNING.test(src) || !/signingConfigs \{\n/.test(src)) {
      // Template changed shape; leave gradle untouched (debug signing still
      // works) rather than risk producing invalid gradle. The release workflow
      // surfaces the missing signature clearly if this ever regresses.
      console.warn(
        "[with-android-signing] expected anchors not found in build.gradle; " +
          "release signing NOT injected (debug signing left in place)",
      );
      return cfg;
    }

    // Point the release build type at the release config when the keystore is
    // present, else keep the debug keystore.
    src = src.replace(
      RELEASE_BUILDTYPE_SIGNING,
      "$1            signingConfig project.hasProperty('VESTA_UPLOAD_STORE_FILE') " +
        "? signingConfigs.release : signingConfigs.debug",
    );
    // Define that release signing config next to the debug one.
    src = src.replace(/(signingConfigs \{\n)/, `$1${RELEASE_SIGNING_CONFIG}`);

    cfg.modResults.contents = src;
    return cfg;
  });
};
